import{_ as a,o,c as l,ag as r}from"./chunks/framework.D2Ob5GRY.js";const m=JSON.parse('{"title":"常见错误与解决方法","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting/common-errors.md","filePath":"troubleshooting/common-errors.md"}'),i={name:"troubleshooting/common-errors.md"};function t(n,e,d,c,h,s){return o(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="常见错误与解决方法" tabindex="-1">常见错误与解决方法 <a class="header-anchor" href="#常见错误与解决方法" aria-label="Permalink to &quot;常见错误与解决方法&quot;">​</a></h1><blockquote><p>启动时账号验证失败、无法连接门户、LLM 调用失败、模块不可用、Docker 容器启动失败等。</p></blockquote><h2 id="启动时「账号验证失败」" tabindex="-1">启动时「账号验证失败」 <a class="header-anchor" href="#启动时「账号验证失败」" aria-label="Permalink to &quot;启动时「账号验证失败」&quot;">​</a></h2><p>主产品启动时会向门户校验账号或授权码，失败时可能报错并退出。根据返回的 <code>error</code> 或 <code>detail</code> 区分处理：</p><h3 id="invalid-credentials-用户名-密码错误" tabindex="-1">invalid_credentials：用户名/密码错误 <a class="header-anchor" href="#invalid-credentials-用户名-密码错误" aria-label="Permalink to &quot;invalid_credentials：用户名/密码错误&quot;">​</a></h3><ul><li><strong>原因</strong>：<code>.env</code> 中 <code>LINSCIO_USERNAME</code> 或 <code>LINSCIO_PASSWORD</code> 与门户账号不一致，或拼写错误。</li><li><strong>处理</strong>：检查 <code>.env</code> 配置，确认与门户登录账号一致；可在终端执行 <code>grep LINSCIO .env</code> 核对（注意不要泄露到公共环境）。修正后重启主产品。</li></ul><h3 id="not-purchased-未购买套餐" tabindex="-1">not_purchased：未购买套餐 <a class="header-anchor" href="#not-purchased-未购买套餐" aria-label="Permalink to &quot;not_purchased：未购买套餐&quot;">​</a></h3><ul><li><strong>原因</strong>：该账号尚未购买或未激活授权，门户拒绝签发令牌。</li><li><strong>处理</strong>：在门户完成套餐购买或使用授权码激活；若为授权码路径，确认授权码已在用户中心激活且未作废。</li></ul><h3 id="account-suspended-账号已停用-需续费" tabindex="-1">account_suspended：账号已停用，需续费 <a class="header-anchor" href="#account-suspended-账号已停用-需续费" aria-label="Permalink to &quot;account_suspended：账号已停用，需续费&quot;">​</a></h3><ul><li><strong>原因</strong>：维护期已到期且超过宽限期，门户将账号置为 suspended，拒绝签发新令牌。</li><li><strong>处理</strong>：联系管理员或在门户办理年维护费续费，延长「维护截止日」后即可恢复；续费后重新启动主产品或等待自动续签。</li></ul><h3 id="machine-limit-exceeded-机器数超限-需解绑旧机器" tabindex="-1">machine_limit_exceeded：机器数超限，需解绑旧机器 <a class="header-anchor" href="#machine-limit-exceeded-机器数超限-需解绑旧机器" aria-label="Permalink to &quot;machine_limit_exceeded：机器数超限，需解绑旧机器&quot;">​</a></h3><ul><li><strong>原因</strong>：当前授权码已绑定机器数达到套餐上限，本机不在已绑定列表中。</li><li><strong>处理</strong>：登录门户用户中心，在「机器管理」或「已绑定机器」中解绑不再使用的机器，然后在本机重新启动主产品完成绑定。</li></ul><hr><h2 id="启动时「无法连接到门户服务器」" tabindex="-1">启动时「无法连接到门户服务器」 <a class="header-anchor" href="#启动时「无法连接到门户服务器」" aria-label="Permalink to &quot;启动时「无法连接到门户服务器」&quot;">​</a></h2><ul><li><strong>原因</strong>：主产品无法访问 <code>LINSCIO_PORTAL</code> 配置的地址（如 <a href="https://api.linscio.com.cn" target="_blank" rel="noreferrer">https://api.linscio.com.cn</a>），多为网络或防火墙问题。</li><li><strong>处理</strong>： <ol><li>在部署机器上执行 <code>curl -I &lt;LINSCIO_PORTAL&gt;/health</code> 或浏览器访问门户健康检查地址，确认能否连通。</li><li>检查防火墙、安全组是否放行出站 HTTPS（443）。</li><li>若在内网，确认是否有代理或网关需配置；主产品需能解析并访问门户域名。</li></ol></li></ul><hr><h2 id="llm-调用失败" tabindex="-1">LLM 调用失败 <a class="header-anchor" href="#llm-调用失败" aria-label="Permalink to &quot;LLM 调用失败&quot;">​</a></h2><h3 id="api-key-无效" tabindex="-1">API Key 无效 <a class="header-anchor" href="#api-key-无效" aria-label="Permalink to &quot;API Key 无效&quot;">​</a></h3><ul><li>返回 401/403 时，多为 API Key 错误、过期或未开通服务。</li><li><strong>处理</strong>：在系统设置中重新填写对应 Provider 的 API Key，或到服务商控制台检查 Key 状态与额度。</li></ul><h3 id="代理配置问题" tabindex="-1">代理配置问题 <a class="header-anchor" href="#代理配置问题" aria-label="Permalink to &quot;代理配置问题&quot;">​</a></h3><ul><li>国内访问 OpenAI/Gemini 等需代理，未配置或代理不可用时会出现连接超时或连接被拒绝。</li><li><strong>处理</strong>：在系统设置「代理配置」中填写正确的 HTTP/HTTPS 代理地址，保存后重试；或改用国内直连的 DeepSeek、通义。</li></ul><h3 id="服务商限速-429-错误" tabindex="-1">服务商限速（429 错误） <a class="header-anchor" href="#服务商限速-429-错误" aria-label="Permalink to &quot;服务商限速（429 错误）&quot;">​</a></h3><ul><li>请求过于频繁触发服务商限流。</li><li><strong>处理</strong>：稍后重试；或配置多个 Provider 利用自动降级分散请求；必要时升级服务商套餐提高限流阈值。</li></ul><hr><h2 id="某个功能模块无法使用" tabindex="-1">某个功能模块无法使用 <a class="header-anchor" href="#某个功能模块无法使用" aria-label="Permalink to &quot;某个功能模块无法使用&quot;">​</a></h2><h3 id="套餐未包含该模块" tabindex="-1">套餐未包含该模块 <a class="header-anchor" href="#套餐未包含该模块" aria-label="Permalink to &quot;套餐未包含该模块&quot;">​</a></h3><ul><li>当前套餐的模块权限不包含该功能，访问时返回 403 <code>module_not_available</code>。</li><li><strong>处理</strong>：升级套餐或联系管理员确认当前套餐包含的模块列表。</li></ul><h3 id="确认模块授权状态" tabindex="-1">确认模块授权状态 <a class="header-anchor" href="#确认模块授权状态" aria-label="Permalink to &quot;确认模块授权状态&quot;">​</a></h3><ul><li>在用户中心或「关于」页查看当前授权与模块列表；若应为可用但仍不可用，请检查主产品与门户版本是否匹配、是否有缓存，必要时重新登录或重启主产品。</li></ul><hr><h2 id="docker-容器启动失败" tabindex="-1">Docker 容器启动失败 <a class="header-anchor" href="#docker-容器启动失败" aria-label="Permalink to &quot;Docker 容器启动失败&quot;">​</a></h2><h3 id="端口被占用" tabindex="-1">端口被占用 <a class="header-anchor" href="#端口被占用" aria-label="Permalink to &quot;端口被占用&quot;">​</a></h3><ul><li>报错 <code>port is already allocated</code> 等。</li><li><strong>处理</strong>：修改 docker-compose 中端口映射（如 8080 改为 8081），或停止占用端口的其他服务。</li></ul><h3 id="内存不足" tabindex="-1">内存不足 <a class="header-anchor" href="#内存不足" aria-label="Permalink to &quot;内存不足&quot;">​</a></h3><ul><li>容器或宿主机内存不足导致 OOM。</li><li><strong>处理</strong>：增加宿主机内存或为容器限制适当内存；关闭其他占用内存的服务。</li></ul><h3 id="镜像加载失败" tabindex="-1">镜像加载失败 <a class="header-anchor" href="#镜像加载失败" aria-label="Permalink to &quot;镜像加载失败&quot;">​</a></h3><ul><li>本地无镜像且拉取失败（网络或仓库不可达）。</li><li><strong>处理</strong>：检查网络与镜像仓库地址；若使用安装包内的镜像 tar，先执行 <code>docker load -i xxx.tar</code> 再启动。</li></ul><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/troubleshooting/performance.html">性能优化建议</a></li><li><a href="/docs/troubleshooting/backup-and-migration.html">数据备份与迁移</a></li><li><a href="/docs/reference/error-codes.html">错误代码参考表</a></li></ul>',40)])])}const b=a(i,[["render",t]]);export{m as __pageData,b as default};
